export function partitionOnce<T>(
  items: readonly T[],
  predicate: (item: T) => boolean,
): { matched: T[]; unmatched: T[] } {
  const matched: T[] = [];
  const unmatched: T[] = [];
  for (const item of items) {
    (predicate(item) ? matched : unmatched).push(item);
  }
  return { matched, unmatched };
}

