export function traverseQueue<T>(
  initial: readonly T[],
  expand: (item: T) => readonly T[],
): T[] {
  const queue: T[] = [...initial];
  const result: T[] = [];
  for (let head = 0; head < queue.length; head += 1) {
    const item = queue[head];
    result.push(item);
    queue.push(...expand(item));
  }
  return result;
}

