function minMax(values) {
  if (!Array.isArray(values) || values.length === 0) {
    throw new TypeError("values must be a non-empty array");
  }
  const first = values[0];
  if (!Number.isFinite(first)) throw new TypeError("values must be finite numbers");
  let min = first;
  let max = first;
  for (let i = 1; i < values.length; i += 1) {
    const value = values[i];
    if (!Number.isFinite(value)) throw new TypeError("values must be finite numbers");
    if (value < min) min = value;
    if (value > max) max = value;
  }
  return { min, max };
}

